import {
  useEffect,
  useRef,
  useState,
  useMemo,
  useCallback,
  forwardRef,
  useImperativeHandle,
  memo,
  type RefObject,
} from "react";
import type React from "react";
import rangeAtIndex from "./vendor/range-at-index.js";
import {
  hasPercentageUnit,
  stopPropagation,
  syncBackdropStyle,
} from "./dom.js";
import { type SelectionRange, initSelectionStore } from "./selection.js";
import { useIsomorphicLayoutEffect } from "./useIsomorphicLayoutEffect.js";
import type { CaretPosition, Renderer } from "./types.js";
import { CARET_DETECTOR, refKey } from "./utils.js";
import { useStatic } from "./useStatic.js";
import { type TextareaRect, createTextareaObserver } from "./observer.js";

type BackdropHandle = (value: string) => void;

const Backdrop /*#__PURE__*/ = memo(
  ({
    _ref: backdropRef,
    _handle: handle,
    _render: render,
    _width: width,
  }: {
    _ref: RefObject<HTMLDivElement | null>;
    _handle: RefObject<BackdropHandle | null>;
    _render: Renderer | undefined;
    _width: number;
  }) => {
    const [value, setValue] = useState("");

    useImperativeHandle(handle, () => setValue, []);

    return (
      <div
        ref={backdropRef}
        aria-hidden
        style={useMemo(
          (): React.CSSProperties => ({
            width,
            transform: "translate(0px, 0px)",
            pointerEvents: "none",
            userSelect: "none",
            msUserSelect: "none",
            WebkitUserSelect: "none",
            // https://github.com/inokawa/rich-textarea/issues/56
            boxSizing: "content-box",
            // https://stackoverflow.com/questions/2545542/font-size-rendering-inconsistencies-on-an-iphone
            textSizeAdjust: "100%",
            WebkitTextSizeAdjust: "100%",
            MozTextSizeAdjust: "100%",
          }),
          [width],
        )}
        // Stop propagation of events dispatched on backdrop
        onClick={stopPropagation}
        onMouseDown={stopPropagation}
        onMouseUp={stopPropagation}
        onMouseOver={stopPropagation}
        onMouseOut={stopPropagation}
        onMouseMove={stopPropagation}
      >
        {useMemo(() => (render ? render(value) : value), [value, render])}
        {CARET_DETECTOR}
      </div>
    );
  },
);

/**
 * Methods of {@link RichTextarea}.
 *
 * All the others not mentioned are proxied to ref of [textarea](https://developer.mozilla.org/en-US/docs/Web/API/HTMLTextAreaElement).
 *
 * | Name              | Type     | Description                                                               |
 * | ----------------- | -------- | ------------------------------------------------------------------------- |
 * | selectionStart    | `number` | Same as original but has handling of composition event                    |
 * | selectionEnd      | `number` | Same as original but has handling of composition event                    |
 * | setRangeText      |          | Same as original but has fallback to `document.execCommand("insertText")` |
 */
export interface RichTextareaHandle extends HTMLTextAreaElement {}

/**
 * Props of {@link RichTextarea}.
 *
 * For other props not mentioned below will be passed to [textarea](https://developer.mozilla.org/en-US/docs/Web/API/HTMLTextAreaElement).
 */
export interface RichTextareaProps
  extends Omit<React.ComponentProps<"textarea">, "children"> {
  /**
   *
   * Render function to create customized view from value.
   *
   * This function should return ReactNodes which texts are positioned the same as textarea (see examples for detailed usage).
   *
   * On the rendered nodes, currently limited event handlers will work.
   * - `onClick`
   * - `onMouseOver`
   * - `onMouseOut`
   * - `onMouseMove`
   * - `onMouseDown`
   * - `onMouseUp`
   * @defaultValue undefined
   */
  children?: Renderer;
  /**
   * If true, textarea height is automatically resized and height of style prop does not work.
   * Set `maxHeight` to style prop if you need limit.
   * Set `rows` prop to 1 if you need single-line textarea.
   * @defaultValue undefined
   */
  autoHeight?: boolean;
  /**
   * Called when selection in textarea changes. It gives position of caret at the time, which is useful to position menu.
   * @defaultValue undefined
   */
  onSelectionChange?: (pos: CaretPosition) => void;
}

/**
 * Textarea component with some extra props. See {@link RichTextareaProps} and {@link RichTextareaHandle}.
 */
export const RichTextarea = /*#__PURE__*/ forwardRef<
  RichTextareaHandle,
  RichTextareaProps
>(
  (
    {
      children: render,
      autoHeight,
      style,
      onChange,
      onKeyDown,
      onSelectionChange,
      ...props
    },
    ref,
  ): React.ReactElement => {
    const textAreaRef = useRef<HTMLTextAreaElement>(null);
    const backdropRef = useRef<HTMLDivElement>(null);
    const backdropHandle = useRef<BackdropHandle>(null);
    const [[width, height, hPadding, vPadding], setRect] =
      useState<TextareaRect>([0, 0, 0, 0]);
    const [focused, setFocused] = useState<boolean>(false);

    const caretColorRef = useRef("");

    const [[selectionStart, selectionEnd], setSelection] =
      useState<SelectionRange>([null, null]);
    const selectionStore = useStatic(() =>
      initSelectionStore(textAreaRef, setSelection),
    );

    const totalWidth = width + hPadding;
    const totalHeight = height + vPadding;

    const isSizeCalculated = !!(totalWidth + totalHeight);

    useImperativeHandle(ref, () => {
      const el = textAreaRef[refKey]!;
      const overrides = {
        get selectionStart() {
          return selectionStore._getSelectionStart();
        },
        get selectionEnd() {
          return selectionStore._getSelectionEnd();
        },
        setRangeText(
          text: string,
          start: number,
          end: number,
          preserve?: SelectionMode,
        ) {
          if (el.setRangeText) {
            el.setRangeText(text, start, end, preserve);
          } else {
            el.focus();
            el.selectionStart = start;
            el.selectionEnd = end;
            document.execCommand("insertText", false, text);
          }
          // Invoke onChange to lift state up
          el.dispatchEvent(new Event("input", { bubbles: true }));
        },
      };

      return new Proxy(el, {
        get(target, prop: keyof HTMLTextAreaElement) {
          if ((overrides as any)[prop]) {
            return (overrides as any)[prop];
          }
          const value = target[prop];
          return typeof value === "function" ? value.bind(target) : value;
        },
        set(target, prop, value) {
          (target as any)[prop] = value;
          return true;
        },
      }) as HTMLTextAreaElement;
    }, []);

    useIsomorphicLayoutEffect(() => {
      const textarea = textAreaRef[refKey];
      const backdrop = backdropRef[refKey];
      if (!textarea || !backdrop) return;

      return createTextareaObserver(
        textarea,
        backdrop,
        selectionStore,
        setRect,
        setFocused,
      );
    }, []);

    useIsomorphicLayoutEffect(() => {
      const textarea = textAreaRef[refKey];
      if (!textarea) return;
      // Sync value on init and change
      backdropHandle[refKey]!(textarea.value);
    }, [props.value]);

    useIsomorphicLayoutEffect(() => {
      // Sync backdrop style
      const textarea = textAreaRef[refKey];
      const backdrop = backdropRef[refKey];
      if (!backdrop || !textarea) return;
      syncBackdropStyle(textarea, backdrop, caretColorRef, style);
    }, [style]);

    useEffect(() => {
      if (selectionStart == null || selectionEnd == null || !onSelectionChange)
        return;
      if (!focused) {
        onSelectionChange({
          focused: false,
          selectionStart: selectionStart,
          selectionEnd: selectionEnd,
        });
      } else {
        const range = rangeAtIndex(
          backdropRef[refKey]!,
          selectionStart,
          selectionStart + 1,
        ) as Range;
        const rect = range.getBoundingClientRect();
        onSelectionChange({
          focused: true,
          top: rect.top,
          left: rect.left,
          height: rect.height,
          selectionStart: selectionStart,
          selectionEnd: selectionEnd,
        });
      }
    }, [focused, selectionStart, selectionEnd]);

    useEffect(() => {
      const textarea = textAreaRef[refKey];
      if (!autoHeight || !textarea) return;
      textarea.style.height = "auto";
      textarea.style.height = `${textarea.scrollHeight}px`;
    });

    return (
      <div
        style={useMemo((): React.CSSProperties => {
          let w: React.CSSProperties["width"] = totalWidth;
          let h: React.CSSProperties["height"] = totalHeight;
          // Prefer prop style to avoid miscalculation https://github.com/inokawa/rich-textarea/issues/39
          if (style) {
            if (hasPercentageUnit(style.width)) {
              w = style.width;
            }
            if (hasPercentageUnit(style.height)) {
              h = style.height;
            }
          }
          return {
            display: "inline-block",
            position: "relative",
            width: w,
            height: h,
          };
        }, [totalWidth, totalHeight, style])}
      >
        <div
          style={useMemo((): React.CSSProperties => {
            const s: React.CSSProperties = {
              position: "absolute",
              overflow: "hidden",
              top: 0,
              left: 0,
              width: totalWidth,
              height: totalHeight,
            };
            if (!style) return s;
            (["background", "backgroundColor"] as const).forEach((k) => {
              if (style[k]) s[k] = style[k] as any;
            });
            return s;
          }, [totalWidth, totalHeight, style])}
        >
          <Backdrop
            _ref={backdropRef}
            _handle={backdropHandle}
            _render={render}
            _width={width}
          />
        </div>
        <textarea
          {...props}
          ref={textAreaRef}
          style={useMemo(
            () => ({
              ...style,
              background: "transparent",
              margin: 0,
              // Set `position: absolute` to fix bug that sometimes texts disappear in Chrome for unknown reason
              position: "absolute",
              // And remove it until element size is calculated to avoid layout shift on mount
              // https://github.com/inokawa/rich-textarea/issues/21
              ...(!isSizeCalculated && {
                position: undefined,
                verticalAlign: "top",
              }),
            }),
            [style, isSizeCalculated],
          )}
          onChange={useCallback(
            (e: React.ChangeEvent<HTMLTextAreaElement>) => {
              backdropHandle[refKey]?.(e.target.value);
              onChange?.(e);
            },
            [onChange],
          )}
          onKeyDown={useCallback(
            (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
              // Ignore keydown events during IME composition.
              // Safari sometimes fires keydown event after compositionend so also ignore it.
              // https://developer.mozilla.org/en-US/docs/Web/API/Document/keydown_event#ignoring_keydown_during_ime_composition
              if (e.nativeEvent.isComposing || e.nativeEvent.keyCode === 229) {
                return;
              }

              onKeyDown?.(e);
              selectionStore._updateSeletion();
            },
            [onKeyDown],
          )}
        />
      </div>
    );
  },
);

import { refKey } from "./utils.js";

/**
 * @internal
 */
export const isSafari = (): boolean => {
  if (typeof navigator === "undefined") {
    return false;
  }
  const ua = navigator.userAgent.toLowerCase();
  return ua.indexOf("safari") > -1 && ua.indexOf("chrome") <= -1;
};

const TEXT_STYLE_KEYS: (keyof React.CSSProperties)[] = [
  "direction",
  "padding",
  "paddingTop",
  "paddingBottom",
  "paddingLeft",
  "paddingRight",
  "margin",
  "marginTop",
  "marginBottom",
  "marginLeft",
  "marginRight",
  "border",
  "borderWidth",
  "borderTopWidth",
  "borderBottomWidth",
  "borderLeftWidth",
  "borderRightWidth",
  "borderStyle",
  "borderTopStyle",
  "borderBottomStyle",
  "borderLeftStyle",
  "borderRightStyle",
  "fontSize",
  "fontFamily",
  "fontStyle",
  "fontVariant",
  "fontWeight",
  "fontStretch",
  "fontSizeAdjust",
  "textAlign",
  "textTransform",
  "textIndent",
  "letterSpacing",
  "wordSpacing",
  "lineHeight",
  "whiteSpace",
  "wordBreak",
  "overflowWrap",
  "tabSize",
  "MozTabSize",
];

const getPropertyValue = (style: CSSStyleDeclaration, key: string): string => {
  return style.getPropertyValue(key);
};
const setProperty = (
  style: CSSStyleDeclaration,
  key: string,
  value: string
) => {
  style.setProperty(key, value);
};

const getValueFromStyle = (style: CSSStyleDeclaration, key: string): number => {
  const value = getPropertyValue(style, key);
  if (!value) {
    return 0;
  } else {
    return parseInt(value, 10);
  }
};

/**
 * @internal
 */
export const getStyle = (e: Element) => getComputedStyle(e);

/**
 * @internal
 */
export const hasPercentageUnit = (
  widthOrHeight: React.CSSProperties["width"] | React.CSSProperties["height"]
): boolean => {
  return typeof widthOrHeight === "string" && widthOrHeight.endsWith("%");
};

/**
 * @internal
 */
export const getVerticalPadding = (style: CSSStyleDeclaration): number => {
  return (
    getValueFromStyle(style, "padding-top") +
    getValueFromStyle(style, "padding-bottom") +
    getValueFromStyle(style, "border-top") +
    getValueFromStyle(style, "border-bottom")
  );
};

/**
 * @internal
 */
export const getHorizontalPadding = (style: CSSStyleDeclaration): number => {
  return (
    getValueFromStyle(style, "padding-left") +
    getValueFromStyle(style, "padding-right") +
    getValueFromStyle(style, "border-left") +
    getValueFromStyle(style, "border-right")
  );
};

/**
 * @internal
 */
export const getPointedElement = (
  textarea: HTMLElement,
  backdrop: HTMLElement,
  e: MouseEvent
): HTMLElement | null => {
  const POINTER_EVENTS = "pointer-events";

  const textareaStyle = textarea.style;
  const backdropStyle = backdrop.style;
  const prev = getPropertyValue(textareaStyle, POINTER_EVENTS);
  const backPrev = getPropertyValue(backdropStyle, POINTER_EVENTS);
  setProperty(textareaStyle, POINTER_EVENTS, "none");
  setProperty(backdropStyle, POINTER_EVENTS, "auto");

  const pointed = document.elementFromPoint(
    e.clientX,
    e.clientY
  ) as HTMLElement | null;

  setProperty(textareaStyle, POINTER_EVENTS, prev);
  setProperty(backdropStyle, POINTER_EVENTS, backPrev);

  if (isInsideBackdrop(pointed, backdrop)) {
    return pointed;
  } else {
    return null;
  }
};

const isInsideBackdrop = (
  pointed: HTMLElement | null,
  backdrop: HTMLElement
): boolean => !!pointed && backdrop !== pointed && backdrop.contains(pointed);

const dispatchMouseEvent = (
  target: HTMLElement,
  type: string,
  init: MouseEventInit
) => {
  target.dispatchEvent(new MouseEvent(type, init));
};

/**
 * @internal
 */
export const dispatchClonedMouseEvent = (
  pointed: HTMLElement,
  e: MouseEvent
) => {
  dispatchMouseEvent(pointed, e.type, e);
};

/**
 * @internal
 */
export const dispatchMouseMoveEvent = (
  pointed: HTMLElement | null,
  prevPointed: HTMLElement | null,
  e: MouseEvent
) => {
  if (pointed) {
    dispatchClonedMouseEvent(pointed, e);
  }

  if (prevPointed !== pointed) {
    dispatchMouseOutEvent(prevPointed, e);
    if (pointed) {
      dispatchMouseEvent(pointed, "mouseover", e);
    }
  }
};

/**
 * @internal
 */
export const dispatchMouseOutEvent = (
  prevPointed: HTMLElement | null,
  e: MouseEvent
) => {
  if (prevPointed) {
    dispatchMouseEvent(prevPointed, "mouseout", e);
  }
};

/**
 * @internal
 */
export const stopPropagation = (event: React.MouseEvent) => {
  event.stopPropagation();
};

/**
 * @internal
 */
export const syncBackdropStyle = (
  textarea: HTMLElement,
  backdrop: HTMLElement,
  caretColorRef: React.MutableRefObject<string>,
  style?: React.CSSProperties
) => {
  const computedTextAreaStyle = getStyle(textarea);
  const textareaStyle = textarea.style;
  const backdropStyle = backdrop.style;
  if (!caretColorRef[refKey]) {
    caretColorRef[refKey] = getPropertyValue(computedTextAreaStyle, "color");
  }

  TEXT_STYLE_KEYS.forEach((k) => {
    backdropStyle[k as any] = computedTextAreaStyle[k as any]!;
  });
  textareaStyle.color = backdropStyle.borderColor = "transparent";
  textareaStyle.caretColor = style?.caretColor || caretColorRef[refKey];
};

/**
 * @internal
 */
export const listenEvent = <
  E extends HTMLElement | Document,
  K extends keyof GlobalEventHandlersEventMap,
>(
  el: E,
  key: K,
  cb: (this: E, ev: GlobalEventHandlersEventMap[K]) => void
) => {
  el.addEventListener(key, cb as EventListenerOrEventListenerObject);
  return () => {
    el.removeEventListener(key, cb as EventListenerOrEventListenerObject);
  };
};

import {
  dispatchClonedMouseEvent,
  dispatchMouseMoveEvent,
  dispatchMouseOutEvent,
  getHorizontalPadding,
  getPointedElement,
  getStyle,
  getVerticalPadding,
  listenEvent,
} from "./dom.js";
import { type SelectionStore } from "./selection.js";

/**
 * @internal
 */
export type TextareaRect = [
  width: number,
  height: number,
  hPadding: number,
  vPadding: number,
];

/**
 * @internal
 */
export const createTextareaObserver = (
  textarea: HTMLTextAreaElement | HTMLInputElement,
  backdrop: HTMLDivElement,
  selectionStore: SelectionStore,
  onResize: (size: TextareaRect) => void,
  onFocus: (value: boolean) => void
) => {
  let prevPointed: HTMLElement | null = null;

  const observer = new ResizeObserver(([entry]) => {
    const {
      contentRect: { width, height },
      borderBoxSize,
    } = entry!;
    if (borderBoxSize && borderBoxSize[0]) {
      onResize([
        width,
        height,
        borderBoxSize[0].inlineSize - width,
        borderBoxSize[0].blockSize - height,
      ]);
      return;
    }
    const style = getStyle(textarea);
    onResize([
      width,
      height,
      getHorizontalPadding(style),
      getVerticalPadding(style),
    ]);
  });

  const cleanUpOnFocus = listenEvent(textarea, "focus", () => {
    onFocus(true);
  });
  const cleanUpOnBlur = listenEvent(textarea, "blur", () => {
    onFocus(false);
  });
  const cleanUpOnScroll = listenEvent(textarea, "scroll", () => {
    const { scrollTop, scrollLeft } = textarea;
    backdrop.style.transform = `translate(${-scrollLeft}px, ${-scrollTop}px)`;
  });
  const cleanUpOnMouseDown = listenEvent(textarea, "mousedown", (e) => {
    selectionStore._updateSeletion();
    const cleanup = listenEvent(document, "mouseup", () => {
      selectionStore._updateSeletion();
      cleanup();
    });
    const pointed = getPointedElement(textarea, backdrop, e);
    if (pointed) {
      dispatchClonedMouseEvent(pointed, e);
    }
  });
  const cleanUpOnMouseUp = listenEvent(textarea, "mouseup", (e) => {
    const pointed = getPointedElement(textarea, backdrop, e);
    if (pointed) {
      dispatchClonedMouseEvent(pointed, e);
    }
  });
  const cleanUpOnMouseMove = listenEvent(textarea, "mousemove", (e) => {
    const p = getPointedElement(textarea, backdrop, e);
    dispatchMouseMoveEvent(p, prevPointed, e);
    prevPointed = p;
  });
  const cleanUpOnMouseLeave = listenEvent(textarea, "mouseleave", (e) => {
    dispatchMouseOutEvent(prevPointed, e);
    prevPointed = null;
  });
  const cleanUpOnClick = listenEvent(textarea, "click", (e) => {
    const pointed = getPointedElement(textarea, backdrop, e);
    if (pointed) {
      dispatchClonedMouseEvent(pointed, e);
    }
  });
  const cleanUpOnInput = listenEvent(textarea, "input", () => {
    selectionStore._updateSeletion();
  });
  const cleanUpOnCompositionStart = listenEvent(
    textarea,
    "compositionstart",
    (e) => {
      selectionStore._setComposition(e);
    }
  );
  const cleanUpOnCompositionUpdate = listenEvent(
    textarea,
    "compositionupdate",
    (e) => {
      selectionStore._setComposition(e);
    }
  );
  const cleanUpOnCompositionEnd = listenEvent(
    textarea,
    "compositionend",
    () => {
      selectionStore._setComposition();
    }
  );
  observer.observe(textarea);
  return () => {
    cleanUpOnFocus();
    cleanUpOnBlur();
    cleanUpOnScroll();
    cleanUpOnMouseDown();
    cleanUpOnMouseUp();
    cleanUpOnMouseMove();
    cleanUpOnMouseLeave();
    cleanUpOnClick();
    cleanUpOnInput();
    cleanUpOnCompositionStart();
    cleanUpOnCompositionUpdate();
    cleanUpOnCompositionEnd();
    observer.disconnect();
  };
};

import { min, refKey } from "./utils.js";

/**
 * @internal
 */
export type SelectionRange = [number | null, number | null];

/**
 * @internal
 */
export const initSelectionStore = (
  ref: React.RefObject<HTMLTextAreaElement | HTMLInputElement | null>,
  onSelectionUpdate: (range: SelectionRange) => void
) => {
  let prevSelection: [number | null, number | null] = [null, null];
  let compositionEvent: CompositionEvent | void;
  const getSelection = (): [number | null, number | null] => {
    const selectionStart = handle._getSelectionStart();
    const selectionEnd = handle._getSelectionEnd();
    if (
      prevSelection[0] === selectionStart &&
      prevSelection[1] === selectionEnd
    ) {
      return prevSelection;
    }
    prevSelection = [selectionStart, selectionEnd];
    return prevSelection;
  };
  const handle = {
    _updateSeletion() {
      setTimeout(() => {
        onSelectionUpdate(getSelection());
      });
    },
    _setComposition(event: CompositionEvent | void) {
      compositionEvent = event;
    },
    _getSelectionStart(): number {
      const el = ref[refKey];
      if (!el) return 0;
      const pos = el.selectionStart!;
      if (!compositionEvent) return pos;
      // compensate selection range during compositioning
      return min(pos, el.selectionEnd! - compositionEvent.data.length);
    },
    _getSelectionEnd(): number {
      const el = ref[refKey];
      if (!el) return 0;
      const pos = el.selectionEnd!;
      // compensate selection range during compositioning
      if (!compositionEvent) return pos;
      return min(pos, el.selectionStart! + compositionEvent.data.length);
    },
  };
  return handle;
};

/**
 * @internal
 */
export type SelectionStore = ReturnType<typeof initSelectionStore>;

import { useRef } from "react";
import { refKey } from "./utils.js";

/**
 * @internal
 */
export const useStatic = <T>(init: () => T): T => {
  const ref = useRef<T>(undefined);
  return ref[refKey] || (ref[refKey] = init());
};

import { useEffect, useLayoutEffect } from "react";

/**
 * https://gist.github.com/gaearon/e7d97cdf38a2907924ea12e4ebdf3c85
 * @internal
 */
export const useIsomorphicLayoutEffect =
  typeof window !== "undefined" ? useLayoutEffect : useEffect;

/**
 * @internal
 */
export const { min, max } = Math;

/**
 * @internal
 */
export const refKey = "current";

/**
 * for caret position detection
 * @internal
 */
export const CARET_DETECTOR = (
  <span style={{ color: "transparent" }}>{"\u200b"}</span>
);

export type Renderer = (value: string) => React.ReactNode;

export type CaretPosition =
  | {
      focused: false;
      selectionStart: number;
      selectionEnd: number;
    }
  | {
      focused: true;
      selectionStart: number;
      selectionEnd: number;
      top: number;
      left: number;
      height: number;
    };

import { max } from "../utils.js";

/**
 * range-at-index
 * https://github.com/webmodules/range-at-index/
 * Nathan Rajlich
 *
 * Forked from version 1.0.4; includes the following modifications:
 * 1) Change module.exports to export default.
 * 2) Fix for https://github.com/inokawa/rich-textarea/issues/160
 **/

/**
 * Returns a Range instance selecting text within HTML Element `el`,
 * at the given `start` and `end` offsets.
 *
 * @param {HTMLElement} el - DOM element to select text within
 * @public
 */

function RangeAtIndex(el, index, offset, range) {
  var doc = el.ownerDocument;
  if (!range) range = doc.createRange();

  let iterator = doc.createNodeIterator(el, NodeFilter.SHOW_TEXT, null, false);

  let start = {};
  let end = {};
  let node, val, len;

  while ((node = iterator.nextNode())) {
    val = node.nodeValue;
    len = val.length;

    if (!start.node && len > index) {
      start.node = node;
      start.offset = index;
    }

    if (!end.node && len >= offset) {
      end.node = node;
      end.offset = offset;
    }

    index -= len;
    offset -= len;
  }

  // update the range with the start and end offsets
  if (start.node) range.setStart(start.node, max(start.offset, 0));
  if (end.node) range.setEnd(end.node, max(end.offset, 0));

  return range;
}

export default RangeAtIndex;

declare function RangeAtIndex(
